contracts/IdentityRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC721/extensions/ERC721URIStorage.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title IdentityRegistry
 * @dev ERC-721 based agent identity contract for APEX
 * @author DR. PRIYA NAIR - VP of Trust & Compliance at APEX
 * @notice Manages agent identity NFTs with IPFS metadata storage
 */
contract IdentityRegistry is ERC721URIStorage, Ownable {

    // State variables
    uint256 private _nextTokenId;
    mapping(address => bool) private _registeredAgents;
    mapping(uint256 => address) private _tokenOwners;

    // Events
    event AgentRegistered(
        uint256 indexed tokenId,
        address indexed agent,
        string cardURI
    );

    /**
     * @dev Constructor
     */
    constructor() ERC721("APEX Agent Identity", "APEX-AI") {
        _nextTokenId = 1;
        _transferOwnership(msg.sender);
    }

    /**
     * @notice Mint a new agent identity NFT
     * @dev Only contract owner can mint new agent identities
     * @param to Address to mint the NFT to
     * @param agentCardURI IPFS URI of the agent card metadata
     * @return tokenId The ID of the newly minted token
     */
    function mintAgentNFT(address to, string memory agentCardURI) 
        external 
        onlyOwner 
        returns (uint256 tokenId) 
    {
        require(to != address(0), "IdentityRegistry: Cannot mint to zero address");
        require(bytes(agentCardURI).length > 0, "IdentityRegistry: Agent card URI required");

        tokenId = _nextTokenId;
        _nextTokenId++;

        _safeMint(to, tokenId);
        _setTokenURI(tokenId, agentCardURI);

        _registeredAgents[to] = true;
        _tokenOwners[tokenId] = to;

        emit AgentRegistered(tokenId, to, agentCardURI);
    }

    /**
     * @notice Get the agent card URI for a token
     * @param tokenId The token ID to query
     * @return The IPFS URI of the agent card
     */
    function getAgentCard(uint256 tokenId) 
        external 
        view 
        returns (string memory) 
    {
        require(ownerOf(tokenId) != address(0), "IdentityRegistry: Token does not exist");
        return tokenURI(tokenId);
    }

    /**
     * @notice Check if an address is a registered agent
     * @param agent The address to check
     * @return True if the address is a registered agent
     */
    function isRegistered(address agent) 
        external 
        view 
        returns (bool) 
    {
        return _registeredAgents[agent];
    }

    /**
     * @notice Get the owner of a token
     * @param tokenId The token ID to query
     * @return The address of the token owner
     */
    function getAgentOwner(uint256 tokenId) 
        external 
        view 
        returns (address) 
    {
        require(ownerOf(tokenId) != address(0), "IdentityRegistry: Token does not exist");
        return ownerOf(tokenId);
    }

    /**
     * @notice Get the next token ID that will be minted
     * @return The next token ID
     */
    function getNextTokenId() 
        external 
        view 
        returns (uint256) 
    {
        return _nextTokenId;
    }

    /**
     * @notice Get total number of registered agents
     * @return Total supply of agent NFTs
     */
    function totalRegisteredAgents() 
        external 
        view 
        returns (uint256) 
    {
        return _nextTokenId;
    }

    // Override required functions
    function _beforeTokenTransfer(
        address from,
        address to,
        uint256 tokenId,
        uint256 batchSize
    ) internal override {
        super._beforeTokenTransfer(from, to, tokenId, batchSize);

        if (from != address(0)) {
            _registeredAgents[from] = false;
        }

        if (to != address(0)) {
            _registeredAgents[to] = true;
            _tokenOwners[tokenId] = to;
        }
    }
}

contracts/ReputationRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

/**
 * @title ReputationRegistry
 * @dev Reputation management contract for APEX agents
 * @author DR. PRIYA NAIR - VP of Trust & Compliance at APEX
 * @notice Manages agent reputation scores with on-chain tracking
 */
contract ReputationRegistry is Ownable, ReentrancyGuard {

    // Structs
    struct ReputationEntry {
        uint256 timestamp;
        uint256 score;
        string tradeId;
        bytes32 outcomeHash;
    }

    // State variables
    mapping(uint256 => uint256) private _reputationScores;
    mapping(uint256 => ReputationEntry[]) private _reputationHistory;
    mapping(address => bool) private _authorizedCallers;

    uint256 private constant MIN_SCORE = 0;
    uint256 private constant MAX_SCORE = 100;
    uint256 private constant MAX_HISTORY_ENTRIES = 100;

    // Events
    event ReputationUpdated(
        uint256 indexed agentTokenId,
        uint256 newScore,
        string tradeId
    );

    /**
     * @dev Constructor
     */
    constructor() {
        _authorizedCallers[msg.sender] = true;
        _transferOwnership(msg.sender);
    }

    /**
     * @notice Update reputation score for an agent
     * @dev Only authorized callers can update reputation
     * @param agentTokenId The token ID of the agent
     * @param delta The score change (positive or negative)
     * @param tradeId The trade identifier
     * @param outcomeHash Hash of the trade outcome data
     */
    function updateReputation(
        uint256 agentTokenId,
        int8 delta,
        string calldata tradeId,
        bytes32 outcomeHash
    ) external nonReentrant onlyAuthorized {
        require(agentTokenId > 0, "ReputationRegistry: Invalid token ID");
        require(bytes(tradeId).length > 0, "ReputationRegistry: Trade ID required");

        uint256 currentScore = _reputationScores[agentTokenId];
        int256 newScoreInt = int256(currentScore) + int256(delta);

        // Enforce score bounds
        if (newScoreInt < int256(MIN_SCORE)) {
            newScoreInt = int256(MIN_SCORE);
        } else if (newScoreInt > int256(MAX_SCORE)) {
            newScoreInt = int256(MAX_SCORE);
        }

        uint256 newScore = uint256(newScoreInt);
        _reputationScores[agentTokenId] = newScore;

        // Add to history
        ReputationEntry memory entry = ReputationEntry({
            timestamp: block.timestamp,
            score: newScore,
            tradeId: tradeId,
            outcomeHash: outcomeHash
        });

        _reputationHistory[agentTokenId].push(entry);

        // Limit history size
        if (_reputationHistory[agentTokenId].length > MAX_HISTORY_ENTRIES) {
            // Remove oldest entry
            for (uint256 i = 0; i < _reputationHistory[agentTokenId].length - 1; i++) {
                _reputationHistory[agentTokenId][i] = _reputationHistory[agentTokenId][i + 1];
            }
            _reputationHistory[agentTokenId].pop();
        }

        emit ReputationUpdated(agentTokenId, newScore, tradeId);
    }

    /**
     * @notice Get the current reputation score for an agent
     * @param agentTokenId The token ID of the agent
     * @return Current reputation score (0-100)
     */
    function getReputation(uint256 agentTokenId) 
        external 
        view 
        returns (uint256) 
    {
        return _reputationScores[agentTokenId];
    }

    /**
     * @notice Get reputation history for an agent
     * @param agentTokenId The token ID of the agent
     * @return Array of reputation entries
     */
    function getHistory(uint256 agentTokenId) 
        external 
        view 
        returns (ReputationEntry[] memory) 
    {
        return _reputationHistory[agentTokenId];
    }

    /**
     * @notice Get the most recent reputation entry for an agent
     * @param agentTokenId The token ID of the agent
     * @return Most recent reputation entry
     */
    function getLastEntry(uint256 agentTokenId) 
        external 
        view 
        returns (ReputationEntry memory) 
    {
        ReputationEntry[] storage history = _reputationHistory[agentTokenId];
        require(history.length > 0, "ReputationRegistry: No history found");
        return history[history.length - 1];
    }

    /**
     * @notice Authorize an address to update reputation
     * @dev Only contract owner can authorize callers
     * @param caller The address to authorize
     * @param authorized Whether to authorize or deauthorize
     */
    function setAuthorizedCaller(address caller, bool authorized) 
        external 
        onlyOwner 
    {
        _authorizedCallers[caller] = authorized;
    }

    /**
     * @notice Check if an address is authorized to update reputation
     * @param caller The address to check
     * @return True if authorized
     */
    function isAuthorized(address caller) 
        external 
        view 
        returns (bool) 
    {
        return _authorizedCallers[caller];
    }

    /**
     * @notice Get score bounds
     * @return minScore Minimum possible score
     * @return maxScore Maximum possible score
     */
    function getScoreBounds() 
        external 
        pure 
        returns (uint256 minScore, uint256 maxScore) 
    {
        return (MIN_SCORE, MAX_SCORE);
    }

    // Modifier
    modifier onlyAuthorized() {
        require(_authorizedCallers[msg.sender], "ReputationRegistry: Caller not authorized");
        _;
    }
}

contracts/ValidationRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";
import "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";

/**
 * @title ValidationRegistry
 * @dev Validation artifact registry for APEX trade decisions
 * @author DR. PRIYA NAIR - VP of Trust & Compliance at APEX
 * @notice Manages validation artifacts with EIP-712 signature verification
 */
contract ValidationRegistry is Ownable, ReentrancyGuard {
    using ECDSA for bytes32;

    // Structs
    struct ValidationRecord {
        bytes32 reasoningChainHash;
        bytes eip712Signature;
        string tradeId;
        uint256 timestamp;
        address validator;
        bool verified;
    }

    // State variables
    mapping(uint256 => ValidationRecord) private _validations;
    mapping(address => bool) private _authorizedValidators;
    uint256 private _nextValidationId;

    // Domain separator for EIP-712
    bytes32 private immutable _domainSeparator;

    // EIP-712 type hash
    bytes32 private constant _VALIDATION_TYPEHASH = keccak256(
        "ValidationRecord(bytes32 reasoningChainHash,bytes eip712Signature,string tradeId,uint256 timestamp,address validator)"
    );

    // Events
    event ValidationSubmitted(
        uint256 indexed validationId,
        string tradeId,
        bytes32 reasoningChainHash
    );

    event ValidationVerified(
        uint256 indexed validationId,
        bool verified
    );

    /**
     * @dev Constructor
     */
    constructor() {
        _nextValidationId = 1;
        _domainSeparator = _buildDomainSeparator();
        _authorizedValidators[msg.sender] = true;
        _transferOwnership(msg.sender);
    }

    /**
     * @notice Submit a validation artifact
     * @dev Only authorized validators can submit validations
     * @param reasoningChainHash Hash of the complete reasoning chain
     * @param eip712Signature EIP-712 signature of the validation
     * @param tradeId The trade identifier
     * @return validationId The ID of the submitted validation
     */
    function submitValidation(
        bytes32 reasoningChainHash,
        bytes memory eip712Signature,
        string calldata tradeId
    ) external nonReentrant onlyAuthorized returns (uint256 validationId) {
        require(reasoningChainHash != bytes32(0), "ValidationRegistry: Reasoning hash required");
        require(eip712Signature.length > 0, "ValidationRegistry: Signature required");
        require(bytes(tradeId).length > 0, "ValidationRegistry: Trade ID required");

        validationId = _nextValidationId;
        _nextValidationId++;

        // Create validation record
        ValidationRecord storage validation = _validations[validationId];
        validation.reasoningChainHash = reasoningChainHash;
        validation.eip712Signature = eip712Signature;
        validation.tradeId = tradeId;
        validation.timestamp = block.timestamp;
        validation.validator = msg.sender;
        validation.verified = false; // Requires explicit verification

        emit ValidationSubmitted(validationId, tradeId, reasoningChainHash);
    }

    /**
     * @notice Verify a validation record
     * @dev Anyone can verify, but verification is recorded
     * @param validationId The ID of the validation to verify
     * @return True if the signature is valid
     */
    function verifyValidation(uint256 validationId) 
        external 
        returns (bool) 
    {
        require(_validations[validationId].timestamp != 0, "ValidationRegistry: Validation does not exist");

        ValidationRecord storage validation = _validations[validationId];

        // Reconstruct the signed message
        bytes32 messageHash = keccak256(
            abi.encodePacked(
                _VALIDATION_TYPEHASH,
                validation.reasoningChainHash,
                keccak256(validation.eip712Signature),
                keccak256(bytes(validation.tradeId)),
                validation.timestamp,
                validation.validator
            )
        );

        // Recover the signer address
        address recoveredSigner = messageHash.toEthSignedMessageHash().recover(
            validation.eip712Signature
        );

        bool isValidSignature = recoveredSigner == validation.validator;
        validation.verified = isValidSignature;

        emit ValidationVerified(validationId, isValidSignature);

        return isValidSignature;
    }

    /**
     * @notice Get a validation record
     * @param validationId The ID of the validation
     * @return The validation record
     */
    function getValidation(uint256 validationId) 
        external 
        view 
        returns (ValidationRecord memory) 
    {
        require(_validations[validationId].timestamp != 0, "ValidationRegistry: Validation does not exist");
        return _validations[validationId];
    }

    /**
     * @notice Check if a validation has been verified
     * @param validationId The ID of the validation
     * @return True if verified
     */
    function isVerified(uint256 validationId) 
        external 
        view 
        returns (bool) 
    {
        return _validations[validationId].verified;
    }

    /**
     * @notice Get all validations for a trade
     * @param tradeId The trade identifier
     * @param maxResults Maximum number of results to return
     * @return Array of validation IDs
     */
    function getValidationsForTrade(string calldata tradeId, uint256 maxResults) 
        external 
        view 
        returns (uint256[] memory) 
    {
        uint256[] memory result = new uint256[](maxResults);
        uint256 count = 0;

        // This is inefficient for production - in practice, you'd want a mapping from tradeId to validationIds
        for (uint256 i = 1; i < _nextValidationId && count < maxResults; i++) {
            if (keccak256(bytes(_validations[i].tradeId)) == keccak256(bytes(tradeId))) {
                result[count] = i;
                count++;
            }
        }

        // Resize array to actual count
        uint256[] memory finalResult = new uint256[](count);
        for (uint256 i = 0; i < count; i++) {
            finalResult[i] = result[i];
        }

        return finalResult;
    }

    /**
     * @notice Authorize an address to submit validations
     * @dev Only contract owner can authorize validators
     * @param validator The address to authorize
     * @param authorized Whether to authorize or deauthorize
     */
    function setAuthorizedValidator(address validator, bool authorized) 
        external 
        onlyOwner 
    {
        _authorizedValidators[validator] = authorized;
    }

    /**
     * @notice Check if an address is authorized to submit validations
     * @param validator The address to check
     * @return True if authorized
     */
    function isAuthorizedValidator(address validator) 
        external 
        view 
        returns (bool) 
    {
        return _authorizedValidators[validator];
    }

    /**
     * @notice Get the next validation ID
     * @return The next validation ID that will be assigned
     */
    function getNextValidationId() 
        external 
        view 
        returns (uint256) 
    {
        return _nextValidationId;
    }

    /**
     * @notice Build domain separator for EIP-712
     * @return Domain separator hash
     */
    function _buildDomainSeparator() internal view returns (bytes32) {
        return keccak256(
            abi.encodePacked(
                "EIP712Domain(string name,string version,uint256 chainId,address verifyingContract)",
                keccak256(bytes("APEX Validation Registry")),
                keccak256(bytes("1")),
                block.chainid,
                address(this)
            )
        );
    }

    // Modifiers
    modifier onlyAuthorized() {
        require(_authorizedValidators[msg.sender], "ValidationRegistry: Caller not authorized");
        _;
    }
}

